firmware_template.source:
#include "apds9960.h"
#include <Wire.h>
#include <SparkFun_APDS9960.h>
static SparkFun_APDS9960 apds;
static int _gesture = 0;
static uint8_t _prox = 0;
static uint16_t _r=0,_g=0,_b=0;
static unsigned long _last = 0;
void apds9960_setup() {
  Wire.begin();
  if (!apds.init()) { Serial.println("[apds9960] Init failed!"); return; }
  apds.enableGestureSensor(true);
  apds.enableProximitySensor(false);
  apds.enableLightSensor(false);
  Serial.println("[apds9960] OK");
}
void apds9960_loop() {
  if (millis()-_last < 100) return;
  _last = millis();
  if (apds.isGestureAvailable()) { _gesture = apds.readGesture(); }
  apds.readProximity(_prox);
  apds.readRedLight(_r); apds.readGreenLight(_g); apds.readBlueLight(_b);
}
int apds9960_get_gesture(){return _gesture;}
uint8_t apds9960_get_proximity(){return _prox;}
uint16_t apds9960_get_red(){return _r;}
uint16_t apds9960_get_green(){return _g;}
uint16_t apds9960_get_blue(){return _b;}
